const aiOutput = $input.first().json.output;

if (!aiOutput) {
  throw new Error('No output received from the Paid Ads Reporting Agent.');
}

const parts = aiOutput.split('---SEPARATOR---');

if (parts.length < 2) {
  throw new Error('AI output missing ---SEPARATOR--- delimiter.');
}

// Extract subject from the HTML or use default
let emailSubject = 'Paid Ads Weekly Report';
const titleMatch = parts[1].match(/<h2[^>]*>(.*?)<\/h2>/i);
if (titleMatch) {
  emailSubject = titleMatch[1].replace(/<[^>]*>/g, '').trim();
}

return [{
  json: {
    slackMessage: parts[0].trim(),
    emailSubject: emailSubject,
    emailHtml: parts[1].trim()
  }
}];
